func (c Chain) Then(h Handler) (Handler, error) {
	if h == nil {
		return nil, errors.New("cannot add a nil handler to the chain")
	}

	for i := range c.constructors {
		handler, err := c.constructors[len(c.constructors)-1-i](h)
		if err != nil {
			return nil, err
		}
		h = handler
	}

	return h, nil
}
